contracts/core/Config.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title Config
 * @notice 参数配置管理合约 - 所有可调参数唯一存储
 * @dev 所有修改必须通过 Timelock，并 emit 新旧值
 */
contract Config is AccessControl, Pausable {
    // ==================== 角色定义 ====================
    bytes32 public constant DAO_ROLE = keccak256("DAO_ROLE");
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
    bytes32 public constant GUARDIAN_ROLE = keccak256("GUARDIAN_ROLE");

    // ==================== 时间常量 ====================
    uint256 public rfqValidityPeriod = 2 hours;              // RFQ有效期
    uint256 public quoteValidityPeriod = 30 minutes;         // 报价有效期
    uint256 public initialFeedDeadline = 10 minutes;         // 初始喂价时限
    uint256 public closingFeedDeadline = 10 minutes;         // 平仓喂价时限
    uint256 public defaultMarginCallDeadline = 12 hours;     // 默认追保截止时间
    uint256 public cryptoMarginCallDeadline = 2 hours;       // 加密货币追保截止时间
    uint256 public settlementArbitrationWindow = 24 hours;   // 平仓结算仲裁窗口
    uint256 public defaultArbitrationWindow = 12 hours;      // 其他场景仲裁窗口

    // ==================== 费率常量 (基点 1 = 0.01%) ====================
    uint256 public creationFee = 1 ether;                    // 建仓手续费：1U
    uint256 public tradingFeeRate = 10;                      // 交易手续费：0.1%
    uint256 public arbitrationFee = 30 ether;                // 仲裁费：30U
    uint256 public nstDiscount = 80;                         // NST折扣：80%

    // ==================== 喂价费用 ====================
    uint256 public feedFee_5_3 = 3 ether;                    // 5-3档：3U
    uint256 public feedFee_7_5 = 5 ether;                    // 7-5档：5U
    uint256 public feedFee_10_7 = 8 ether;                   // 10-7档：8U
    uint256 public feedPlatformShare = 10;                   // 平台抽成：10%
    uint256 public feedFeederShare = 90;                     // 喂价员分配：90%

    // ==================== 保证金参数 ====================
    uint256 public minMarginRate = 1000;                     // 最低保证金率：10%（自由卖方）
    uint256 public seatSellerInitialMargin = 0;              // 席位卖方初始保证金：0

    // ==================== 喂价员参数 ====================
    uint256 public minFeederStake = 100 ether;               // 喂价员最低质押：100U

    // ==================== 限制参数 ====================
    uint256 public maxQuotesPerBuyerOrder = 5;               // 买方单最大报价数
    uint256 public maxQuotesPerSellerOrder = 1;              // 卖方单报价即成交
    uint256 public maxConsecutiveDays = 10;                  // 最大连续天数
    uint256 public defaultDailyLimitPercent = 30;            // 默认单日涨幅阈值
    uint256 public minExerciseDelay = 1;                     // 最小行权延迟T+1
    uint256 public maxExerciseDelay = 5;                     // 最大行权延迟T+5

    // ==================== 积分参数 ====================
    uint256 public pointsMultiplier = 100;                   // 积分倍率：1U = 100分

    // ==================== 违约金参数 ====================
    uint256 public initialFeedPenaltyRate = 500;             // 初始喂价超时违约金：5% (基点)
    uint256 public closingFeedPenaltyRate = 500;             // 平仓喂价超时违约金：5% (基点)

    // ==================== 资金池分配比例 (基点 100 = 1%) ====================
    uint256 public nodeRewardShare = 500;                    // 节点奖励：5%
    uint256 public tokenBuybackShare = 1000;                 // 代币回购：10%
    uint256 public lpPoolShare = 1000;                       // LP池：10%
    uint256 public teamFundShare = 3000;                     // 团队：30%
    uint256 public foundationShare = 2500;                   // 基金会：25%
    uint256 public daoShare = 1000;                          // DAO：10%
    uint256 public growthNodeShare = 1000;                   // 成长节点：10%

    // ==================== NST 代币折扣 (P1) ====================
    uint256 public nstDiscountRate = 8000;                   // NST支付折扣：80% (8000基点 = 80%)
    bool public nstDiscountEnabled = true;                   // 启用NST折扣


    // ==================== 合约地址 ====================
    address public usdtAddress;
    address public usdcAddress;
    address public nstTokenAddress;
    address public vaultManagerAddress;
    address public optionsCoreAddress;
    address public feedProtocolAddress;
    address public seatManagerAddress;
    address public pointsManagerAddress;

    // ==================== 事件 ====================
    event ParameterUpdated(
        string indexed paramName,
        uint256 oldValue,
        uint256 newValue,
        uint256 timestamp
    );

    event AddressUpdated(
        string indexed paramName,
        address oldAddress,
        address newAddress,
        uint256 timestamp
    );

    // ==================== 构造函数 ====================
    constructor(address _admin) {
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(DAO_ROLE, _admin);
        _grantRole(OPERATOR_ROLE, _admin);
        _grantRole(GUARDIAN_ROLE, _admin);
    }

    // ==================== 修改器 ====================
    modifier onlyDAO() {
        require(hasRole(DAO_ROLE, msg.sender), "Config: caller is not DAO");
        _;
    }

    modifier onlyOperator() {
        require(hasRole(OPERATOR_ROLE, msg.sender), "Config: caller is not Operator");
        _;
    }

    modifier onlyGuardian() {
        require(hasRole(GUARDIAN_ROLE, msg.sender), "Config: caller is not Guardian");
        _;
    }

    // ==================== 暂停功能 ====================
    function pause() external onlyGuardian {
        _pause();
    }

    function unpause() external onlyDAO {
        _unpause();
    }

    // ==================== 参数设置函数 ====================
    
    /**
     * @notice 设置 RFQ 有效期
     */
    function setRfqValidityPeriod(uint256 _value) external onlyDAO {
        uint256 oldValue = rfqValidityPeriod;
        rfqValidityPeriod = _value;
        emit ParameterUpdated("rfqValidityPeriod", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置报价有效期
     */
    function setQuoteValidityPeriod(uint256 _value) external onlyDAO {
        uint256 oldValue = quoteValidityPeriod;
        quoteValidityPeriod = _value;
        emit ParameterUpdated("quoteValidityPeriod", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置建仓手续费
     */
    function setCreationFee(uint256 _value) external onlyDAO {
        uint256 oldValue = creationFee;
        creationFee = _value;
        emit ParameterUpdated("creationFee", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置交易手续费率
     */
    function setTradingFeeRate(uint256 _value) external onlyDAO {
        uint256 oldValue = tradingFeeRate;
        tradingFeeRate = _value;
        emit ParameterUpdated("tradingFeeRate", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置仲裁费
     */
    function setArbitrationFee(uint256 _value) external onlyDAO {
        uint256 oldValue = arbitrationFee;
        arbitrationFee = _value;
        emit ParameterUpdated("arbitrationFee", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置最低保证金率
     */
    function setMinMarginRate(uint256 _value) external onlyDAO {
        uint256 oldValue = minMarginRate;
        minMarginRate = _value;
        emit ParameterUpdated("minMarginRate", oldValue, _value, block.timestamp);
    }

    /**
     * @notice 设置喂价员最低质押
     */
    function setMinFeederStake(uint256 _value) external onlyDAO {
        uint256 oldValue = minFeederStake;
        minFeederStake = _value;
        emit ParameterUpdated("minFeederStake", oldValue, _value, block.timestamp);
    }

    // ==================== 地址设置函数 ====================

    /**
     * @notice 设置 USDT 地址
     */
    function setUsdtAddress(address _address) external onlyDAO {
        address oldAddress = usdtAddress;
        usdtAddress = _address;
        emit AddressUpdated("usdtAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 VaultManager 地址
     */
    function setVaultManagerAddress(address _address) external onlyDAO {
        address oldAddress = vaultManagerAddress;
        vaultManagerAddress = _address;
        emit AddressUpdated("vaultManagerAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 OptionsCore 地址
     */
    function setOptionsCoreAddress(address _address) external onlyDAO {
        address oldAddress = optionsCoreAddress;
        optionsCoreAddress = _address;
        emit AddressUpdated("optionsCoreAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 FeedProtocol 地址
     */
    function setFeedProtocolAddress(address _address) external onlyDAO {
        address oldAddress = feedProtocolAddress;
        feedProtocolAddress = _address;
        emit AddressUpdated("feedProtocolAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 SeatManager 地址
     */
    function setSeatManagerAddress(address _address) external onlyDAO {
        address oldAddress = seatManagerAddress;
        seatManagerAddress = _address;
        emit AddressUpdated("seatManagerAddress", oldAddress, _address, block.timestamp);
    }

    /**
     * @notice 设置 PointsManager 地址
     */
    function setPointsManagerAddress(address _address) external onlyDAO {
        address oldAddress = pointsManagerAddress;
        pointsManagerAddress = _address;
        emit AddressUpdated("pointsManagerAddress", oldAddress, _address, block.timestamp);
    }

    // ==================== 查询函数 ====================

    /**
     * @notice 获取喂价费用
     * @param tier 喂价档位 (0=5-3, 1=7-5, 2=10-7)
     */
    function getFeedFee(uint8 tier) external view returns (uint256) {
        if (tier == 0) return feedFee_5_3;
        if (tier == 1) return feedFee_7_5;
        if (tier == 2) return feedFee_10_7;
        revert("Config: invalid feed tier");
    }

    /**
     * @notice 获取追保截止时间
     * @param isCrypto 是否为加密货币/外汇
     */
    function getMarginCallDeadline(bool isCrypto) external view returns (uint256) {
        return isCrypto ? cryptoMarginCallDeadline : defaultMarginCallDeadline;
    }

    /**
     * @notice 获取仲裁窗口
     * @param isSettlement 是否为平仓结算
     */
    function getArbitrationWindow(bool isSettlement) external view returns (uint256) {
        return isSettlement ? settlementArbitrationWindow : defaultArbitrationWindow;
    }

    // ==================== NST 折扣函数 (P1) ====================

    /**
     * @notice 计算 NST 折扣后的费用
     * @param originalFee 原始费用
     * @return 折扣后的费用（使用 NST 支付时为 80%）
     */
    function getDiscountedFee(uint256 originalFee) external view returns (uint256) {
        if (!nstDiscountEnabled) {
            return originalFee;
        }
        // nstDiscountRate = 8000 表示 80%
        return (originalFee * nstDiscountRate) / 10000;
    }

    /**
     * @notice 设置 NST 折扣率
     * @param _rate 折扣率（基点，8000 = 80%）
     */
    function setNstDiscountRate(uint256 _rate) external onlyDAO {
        require(_rate > 0 && _rate <= 10000, "Config: invalid discount rate");
        uint256 oldValue = nstDiscountRate;
        nstDiscountRate = _rate;
        emit ParameterUpdated("nstDiscountRate", oldValue, _rate, block.timestamp);
    }

    /**
     * @notice 启用/禁用 NST 折扣
     */
    function setNstDiscountEnabled(bool _enabled) external onlyDAO {
        nstDiscountEnabled = _enabled;
    }
}

contracts/core/OptionsCore.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../libraries/NSTTypes.sol";
import "../interfaces/IOptionsCore.sol";
import "../vault/VaultManager.sol";
import "./Config.sol";

/**
 * @title OptionsCore
 * @notice 期权核心合约 - 订单创建、撮合、喂价
 * @dev 结算/保证金/仲裁功能已拆分到 OptionsSettlement 合约
 */
contract OptionsCore is IOptionsCore, AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    // ==================== 角色定义 ====================
    bytes32 public constant FEED_PROTOCOL_ROLE = keccak256("FEED_PROTOCOL_ROLE");
    bytes32 public constant SETTLEMENT_ROLE = keccak256("SETTLEMENT_ROLE");

    // ==================== 状态变量 ====================
    Config public config;
    VaultManager public vaultManager;
    IERC20 public usdt;

    uint256 public nextOrderId = 1;
    uint256 public nextQuoteId = 1;

    // 订单存储
    mapping(uint256 => Order) public orders;
    mapping(uint256 => Quote[]) public orderQuotes;
    mapping(uint256 => Quote) public quotes;

    // 用户订单索引
    mapping(address => uint256[]) public buyerOrders;
    mapping(address => uint256[]) public sellerOrders;

    // 订单检索索引
    mapping(string => uint256[]) private ordersByCountry;
    mapping(string => uint256[]) private ordersByMarket;
    mapping(string => uint256[]) private ordersByCode;

    // ==================== 构造函数 ====================
    constructor(
        address _config,
        address _vaultManager,
        address _usdt,
        address _admin
    ) {
        config = Config(_config);
        vaultManager = VaultManager(_vaultManager);
        usdt = IERC20(_usdt);
        
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
    }

    // ==================== 修改器 ====================
    modifier validOrder(uint256 orderId) {
        require(orderId > 0 && orderId < nextOrderId, "OptionsCore: invalid order id");
        _;
    }

    modifier onlyBuyer(uint256 orderId) {
        require(msg.sender == orders[orderId].buyer, "OptionsCore: not buyer");
        _;
    }

    modifier onlySeller(uint256 orderId) {
        require(msg.sender == orders[orderId].seller, "OptionsCore: not seller");
        _;
    }

    modifier inStatus(uint256 orderId, OrderStatus status) {
        require(orders[orderId].status == status, "OptionsCore: invalid status");
        _;
    }

    // ==================== 买方功能 ====================

    /**
     * @notice 买方创建询价订单
     */
    function createBuyerRFQ(
        string calldata underlyingName,
        string calldata underlyingCode,
        string calldata market,
        string calldata country,
        string calldata refPrice,
        Direction direction,
        uint256 notionalUSDT,
        uint256 expiryTimestamp,
        uint256 maxPremiumRate,
        uint256 minMarginRate,
        SellerType acceptedSellerType,
        address designatedSeller,
        uint256 arbitrationWindow,
        uint256 marginCallDeadline,
        bool dividendAdjustment,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent,
        FeedRule feedRule
    ) external override nonReentrant whenNotPaused returns (uint256 orderId) {
        require(notionalUSDT > 0, "OptionsCore: notional must be positive");
        require(expiryTimestamp > block.timestamp, "OptionsCore: expiry must be in future");

        // 收取建仓手续费 1U（通过 VaultManager 正式入账到利润池）
        vaultManager.collectFee(msg.sender, address(usdt), config.creationFee(), "creation_fee");

        orderId = nextOrderId++;
        Order storage order = orders[orderId];
        order.orderId = orderId;
        order.buyer = msg.sender;
        order.underlyingName = underlyingName;
        order.underlyingCode = underlyingCode;
        order.market = market;
        order.country = country;
        order.refPrice = refPrice;
        order.direction = direction;
        order.notionalUSDT = notionalUSDT;
        order.expiryTimestamp = expiryTimestamp;
        order.maxPremiumRate = maxPremiumRate;
        order.minMarginRate = minMarginRate;
        order.sellerType = acceptedSellerType;
        order.designatedSeller = designatedSeller;
        order.arbitrationWindow = arbitrationWindow;
        order.marginCallDeadline = marginCallDeadline;
        order.dividendAdjustment = dividendAdjustment;
        order.exerciseDelay = 0;
        // 新增：平仓规则和喂价规则
        order.liquidationRule = liquidationRule;
        order.consecutiveDays = consecutiveDays;
        order.dailyLimitPercent = dailyLimitPercent;
        order.feedRule = feedRule;
        order.status = OrderStatus.RFQ_CREATED;
        order.createdAt = block.timestamp;

        buyerOrders[msg.sender].push(orderId);
        ordersByCountry[country].push(orderId);
        ordersByMarket[market].push(orderId);
        ordersByCode[underlyingCode].push(orderId);

        emit OrderCreated(orderId, msg.sender, true, block.timestamp);
        emit OrderStatusChanged(orderId, OrderStatus.RFQ_CREATED, OrderStatus.RFQ_CREATED, "created", block.timestamp);

        return orderId;
    }

    /**
     * @notice 买方选择卖方报价成交
     */
    function acceptQuote(uint256 quoteId) external override nonReentrant whenNotPaused {
        Quote storage quote = quotes[quoteId];
        require(quote.status == QuoteStatus.Active, "OptionsCore: quote not active");
        require(block.timestamp <= quote.expiresAt, "OptionsCore: quote expired");

        Order storage order = orders[quote.orderId];
        require(msg.sender == order.buyer, "OptionsCore: not buyer");

        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.MATCHED;
        order.seller = quote.seller;
        order.premiumAmount = quote.premiumAmount;
        order.initialMargin = quote.marginAmount;
        order.currentMargin = quote.marginAmount;
        order.liquidationRule = quote.liquidationRule;
        order.consecutiveDays = quote.consecutiveDays;
        order.dailyLimitPercent = quote.dailyLimitPercent;
        order.matchedAt = block.timestamp;

        uint256 tradingFee = (order.notionalUSDT * config.tradingFeeRate()) / 10000;
        // 权利金存入买方保证金账户（结算时由 transferMargin 划给卖方）
        vaultManager.depositMargin(msg.sender, address(usdt), quote.premiumAmount);
        // 交易手续费入利润池
        vaultManager.collectFee(msg.sender, address(usdt), tradingFee, "trading_fee");

        sellerOrders[quote.seller].push(order.orderId);

        // 将其他报价设为拒绝
        Quote[] storage allQuotes = orderQuotes[order.orderId];
        for (uint256 i = 0; i < allQuotes.length; i++) {
            if (allQuotes[i].quoteId != quoteId && allQuotes[i].status == QuoteStatus.Active) {
                allQuotes[i].status = QuoteStatus.Rejected;
            }
        }

        emit OrderMatched(order.orderId, order.buyer, order.seller, block.timestamp);
        emit OrderStatusChanged(order.orderId, oldStatus, OrderStatus.MATCHED, "quote accepted", block.timestamp);
    }

    /**
     * @notice 买方直接承接卖方挂单
     */
    function acceptSellerOrder(uint256 orderId) external 
        validOrder(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(order.status == OrderStatus.RFQ_CREATED, "OptionsCore: order not available");
        require(order.seller != address(0), "OptionsCore: not a seller order");
        require(msg.sender != order.seller, "OptionsCore: cannot accept own order");

        order.buyer = msg.sender;
        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.MATCHED;
        order.matchedAt = block.timestamp;

        uint256 tradingFee = (order.notionalUSDT * config.tradingFeeRate()) / 10000;
        // 权利金存入买方保证金账户（结算时由 transferMargin 划给卖方）
        vaultManager.depositMargin(msg.sender, address(usdt), order.premiumAmount);
        // 交易手续费入利润池
        vaultManager.collectFee(msg.sender, address(usdt), tradingFee, "trading_fee");

        buyerOrders[msg.sender].push(orderId);
        
        emit OrderMatched(order.orderId, order.buyer, order.seller, block.timestamp);
        emit OrderStatusChanged(order.orderId, oldStatus, OrderStatus.MATCHED, "seller order accepted", block.timestamp);
    }

    /**
     * @notice 买方发起喂价请求（发射事件供 FeedEngine 监听）
     */
    function requestFeed(uint256 orderId, FeedTier tier) external payable override 
        validOrder(orderId) 
        onlyBuyer(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];

        FeedType feedType;
        if (order.status == OrderStatus.MATCHED) {
            feedType = FeedType.Initial;
            OrderStatus oldStatus = order.status;
            order.status = OrderStatus.WAITING_INITIAL_FEED;
            emit OrderStatusChanged(orderId, oldStatus, OrderStatus.WAITING_INITIAL_FEED, "initial feed requested", block.timestamp);
        } else if (order.status == OrderStatus.WAITING_FINAL_FEED) {
            feedType = FeedType.Final;
        } else if (order.status == OrderStatus.LIVE) {
            feedType = FeedType.Dynamic;
        } else {
            revert("OptionsCore: invalid status for feed request");
        }

        emit FeedRequestEmitted(
            orderId,
            order.underlyingCode,
            order.market,
            order.country,
            feedType,
            tier,
            msg.sender,
            order.notionalUSDT,
            block.timestamp
        );
    }

    /**
     * @notice 买方取消未成交的RFQ
     */
    function cancelRFQ(uint256 orderId) external override 
        validOrder(orderId) 
        onlyBuyer(orderId) 
        nonReentrant 
        whenNotPaused 
    {
        Order storage order = orders[orderId];
        require(
            order.status == OrderStatus.RFQ_CREATED || order.status == OrderStatus.QUOTING,
            "OptionsCore: cannot cancel after match"
        );
        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.CANCELLED;

        emit OrderCancelled(orderId, "buyer cancelled", block.timestamp);
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.CANCELLED, "buyer cancelled", block.timestamp);
    }

    // ==================== 卖方功能 ====================

    /**
     * @notice 卖方创建卖单
     */
    function createSellerOrder(
        string calldata underlyingName,
        string calldata underlyingCode,
        string calldata market,
        string calldata country,
        string calldata refPrice,
        Direction direction,
        uint256 notionalUSDT,
        uint256 expiryTimestamp,
        uint256 premiumRate,
        uint256 marginAmount,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent,
        uint256 arbitrationWindow,
        bool dividendAdjustment,
        uint8 exerciseDelay,
        FeedRule feedRule
    ) external override nonReentrant whenNotPaused returns (uint256 orderId) {
        require(notionalUSDT > 0, "OptionsCore: notional must be positive");
        require(expiryTimestamp > block.timestamp, "OptionsCore: expiry must be in future");

        // 手续费入利润池，保证金入卖方保证金账户
        vaultManager.collectFee(msg.sender, address(usdt), config.creationFee(), "creation_fee");
        vaultManager.depositMargin(msg.sender, address(usdt), marginAmount);

        orderId = nextOrderId++;
        Order storage order = orders[orderId];
        order.orderId = orderId;
        order.seller = msg.sender;
        order.underlyingName = underlyingName;
        order.underlyingCode = underlyingCode;
        order.market = market;
        order.country = country;
        order.refPrice = refPrice;
        order.direction = direction;
        order.notionalUSDT = notionalUSDT;
        order.expiryTimestamp = expiryTimestamp;
        order.premiumAmount = (notionalUSDT * premiumRate) / 10000;
        order.initialMargin = marginAmount;
        order.currentMargin = marginAmount;
        order.liquidationRule = liquidationRule;
        order.consecutiveDays = consecutiveDays;
        order.dailyLimitPercent = dailyLimitPercent;
        order.arbitrationWindow = arbitrationWindow;
        order.dividendAdjustment = dividendAdjustment;
        order.exerciseDelay = exerciseDelay;
        order.feedRule = feedRule;
        order.status = OrderStatus.RFQ_CREATED;
        order.createdAt = block.timestamp;

        sellerOrders[msg.sender].push(orderId);
        ordersByCountry[country].push(orderId);
        ordersByMarket[market].push(orderId);
        ordersByCode[underlyingCode].push(orderId);

        emit OrderCreated(orderId, msg.sender, false, block.timestamp);

        return orderId;
    }

    /**
     * @notice 卖方对买方RFQ报价
     */
    function submitQuote(
        uint256 orderId,
        uint256 premiumRate,
        uint256 marginRate,
        LiquidationRule liquidationRule,
        uint8 consecutiveDays,
        uint8 dailyLimitPercent
    ) external override validOrder(orderId) nonReentrant whenNotPaused returns (uint256 quoteId) {
        Order storage order = orders[orderId];
        require(
            order.status == OrderStatus.RFQ_CREATED || order.status == OrderStatus.QUOTING,
            "OptionsCore: order not accepting quotes"
        );

        uint256 premiumAmount = (order.notionalUSDT * premiumRate) / 10000;
        uint256 marginAmount = (order.notionalUSDT * marginRate) / 10000;

        if (order.maxPremiumRate > 0) {
            require(premiumRate <= order.maxPremiumRate, "OptionsCore: premium rate too high");
        }
        require(marginRate >= order.minMarginRate, "OptionsCore: margin rate too low");

        // 报价保证金入卖方保证金账户
        vaultManager.depositMargin(msg.sender, address(usdt), marginAmount);

        quoteId = nextQuoteId++;

        Quote memory quote = Quote({
            quoteId: quoteId,
            orderId: orderId,
            seller: msg.sender,
            sellerType: SellerType.FreeSeller,
            premiumRate: premiumRate,
            premiumAmount: premiumAmount,
            marginRate: marginRate,
            marginAmount: marginAmount,
            createdAt: block.timestamp,
            expiresAt: block.timestamp + 24 hours,
            status: QuoteStatus.Active,
            liquidationRule: liquidationRule,
            consecutiveDays: consecutiveDays,
            dailyLimitPercent: dailyLimitPercent
        });

        quotes[quoteId] = quote;
        orderQuotes[orderId].push(quote);

        if (order.status == OrderStatus.RFQ_CREATED) {
            order.status = OrderStatus.QUOTING;
        }

        emit QuoteSubmitted(orderId, quoteId, msg.sender, premiumRate, block.timestamp);

        return quoteId;
    }

    // ==================== Settlement 跨合约写入接口 ====================

    /**
     * @notice 更新订单状态（仅 Settlement 合约可调用）
     */
    function updateOrderStatus(uint256 orderId, OrderStatus newStatus) external 
        validOrder(orderId) onlyRole(SETTLEMENT_ROLE) 
    {
        orders[orderId].status = newStatus;
    }

    /**
     * @notice 更新订单保证金（仅 Settlement 合约可调用）
     */
    function updateOrderMargin(uint256 orderId, uint256 newMargin) external 
        validOrder(orderId) onlyRole(SETTLEMENT_ROLE) 
    {
        orders[orderId].currentMargin = newMargin;
    }

    /**
     * @notice 更新订单价格（仅 Settlement 合约可调用）
     */
    function updateOrderPrice(uint256 orderId, uint256 newPrice) external 
        validOrder(orderId) onlyRole(SETTLEMENT_ROLE) 
    {
        orders[orderId].lastFeedPrice = newPrice;
    }

    /**
     * @notice 更新订单结算时间（仅 Settlement 合约可调用）
     */
    function updateOrderSettledAt(uint256 orderId, uint256 timestamp) external 
        validOrder(orderId) onlyRole(SETTLEMENT_ROLE) 
    {
        orders[orderId].settledAt = timestamp;
    }

    /**
     * @notice 更新追保截止时间（仅 Settlement 合约可调用）
     */
    function updateOrderMarginCallDeadline(uint256 orderId, uint256 deadline) external 
        validOrder(orderId) onlyRole(SETTLEMENT_ROLE) 
    {
        orders[orderId].marginCallDeadline = deadline;
    }

    /**
     * @notice 更新订单累计分红（仅 Settlement 合约可调用）
     */
    function updateOrderDividend(uint256 orderId, uint256 amount) external 
        validOrder(orderId) onlyRole(SETTLEMENT_ROLE) 
    {
        orders[orderId].dividendAmount = amount;
    }

    // ==================== 查询功能 ====================

    function getOrder(uint256 orderId) external view override returns (Order memory) {
        return orders[orderId];
    }

    function getQuotes(uint256 orderId) external view override returns (Quote[] memory) {
        return orderQuotes[orderId];
    }

    function getBuyerOrders(address buyer) external view override returns (uint256[] memory) {
        return buyerOrders[buyer];
    }

    function getSellerOrders(address seller) external view override returns (uint256[] memory) {
        return sellerOrders[seller];
    }

    function getOrdersByCountry(string calldata country) external view returns (uint256[] memory) {
        return ordersByCountry[country];
    }

    function getOrdersByMarket(string calldata market) external view returns (uint256[] memory) {
        return ordersByMarket[market];
    }

    // ==================== 管理功能 ====================

    function setConfig(address _config) external onlyRole(DEFAULT_ADMIN_ROLE) {
        config = Config(_config);
    }

    function setVaultManager(address _vaultManager) external onlyRole(DEFAULT_ADMIN_ROLE) {
        vaultManager = VaultManager(_vaultManager);
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    // ==================== 喂价回调 ====================

    /**
     * @notice 处理期初喂价结果
     */
    function processInitialFeedResult(
        uint256 orderId, 
        uint256 initialPrice
    ) external validOrder(orderId) onlyRole(DEFAULT_ADMIN_ROLE) {
        Order storage order = orders[orderId];
        require(order.status == OrderStatus.MATCHED, "OptionsCore: order not matched");
        
        order.lastFeedPrice = initialPrice;
        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.LIVE;
        
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.LIVE, "initial feed", block.timestamp);
    }

    /**
     * @notice 处理期末喂价结果
     */
    function processFinalFeedResult(
        uint256 orderId, 
        uint256 finalPrice
    ) external validOrder(orderId) onlyRole(DEFAULT_ADMIN_ROLE) {
        Order storage order = orders[orderId];
        require(
            order.status == OrderStatus.LIVE || order.status == OrderStatus.WAITING_FINAL_FEED, 
            "OptionsCore: invalid status"
        );
        
        order.lastFeedPrice = finalPrice;
        OrderStatus oldStatus = order.status;
        order.status = OrderStatus.PENDING_SETTLEMENT;
        
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.PENDING_SETTLEMENT, "final feed", block.timestamp);
    }

    /**
     * @notice FeedEngine 喂价完成后自动回调
     */
    function processFeedCallback(
        uint256 orderId, 
        FeedType feedType, 
        uint256 finalPrice
    ) external override validOrder(orderId) onlyRole(FEED_PROTOCOL_ROLE) {
        Order storage order = orders[orderId];
        require(finalPrice > 0, "OptionsCore: invalid price");

        if (feedType == FeedType.Initial) {
            require(
                order.status == OrderStatus.MATCHED || order.status == OrderStatus.WAITING_INITIAL_FEED,
                "OptionsCore: not awaiting initial feed"
            );
            order.lastFeedPrice = finalPrice;
            OrderStatus oldStatus = order.status;
            order.status = OrderStatus.LIVE;
            emit OrderStatusChanged(orderId, oldStatus, OrderStatus.LIVE, "initial feed callback", block.timestamp);

        } else if (feedType == FeedType.Final) {
            require(
                order.status == OrderStatus.LIVE || order.status == OrderStatus.WAITING_FINAL_FEED,
                "OptionsCore: not awaiting final feed"
            );
            order.lastFeedPrice = finalPrice;
            OrderStatus oldStatus = order.status;
            order.status = OrderStatus.PENDING_SETTLEMENT;
            order.settledAt = block.timestamp;
            emit OrderStatusChanged(orderId, oldStatus, OrderStatus.PENDING_SETTLEMENT, "final feed callback", block.timestamp);
        }
    }

    /**
     * @notice 将 uint256 转换为字符串
     */
    function _uintToString(uint256 value) internal pure returns (string memory) {
        if (value == 0) {
            return "0";
        }
        uint256 temp = value;
        uint256 digits;
        while (temp != 0) {
            digits++;
            temp /= 10;
        }
        bytes memory buffer = new bytes(digits);
        while (value != 0) {
            digits -= 1;
            buffer[digits] = bytes1(uint8(48 + uint256(value % 10)));
            value /= 10;
        }
        return string(buffer);
    }
}

contracts/core/OptionsSettlement.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../libraries/NSTTypes.sol";
import "../interfaces/IOptionsSettlement.sol";
import "../vault/VaultManager.sol";
import "./Config.sol";

/**
 * @title IOptionsCoreForSettlement
 * @notice OptionsCore 暴露给 Settlement 合约的读写接口
 */
interface IOptionsCoreForSettlement {
    function getOrder(uint256 orderId) external view returns (Order memory);
    function nextOrderId() external view returns (uint256);
    
    // 写入接口（由 OptionsCore 新增，仅 SETTLEMENT_ROLE 可调用）
    function updateOrderStatus(uint256 orderId, OrderStatus newStatus) external;
    function updateOrderMargin(uint256 orderId, uint256 newMargin) external;
    function updateOrderPrice(uint256 orderId, uint256 newPrice) external;
    function updateOrderSettledAt(uint256 orderId, uint256 timestamp) external;
    function updateOrderMarginCallDeadline(uint256 orderId, uint256 deadline) external;
    function updateOrderDividend(uint256 orderId, uint256 amount) external;
}

/**
 * @title OptionsSettlement
 * @notice 期权结算合约 — 结算、保证金管理、仲裁、清算
 * @dev 从 OptionsCore 拆分出来，通过跨合约调用读写订单数据
 */
contract OptionsSettlement is IOptionsSettlement, AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    // ==================== 状态变量 ====================
    IOptionsCoreForSettlement public optionsCore;
    Config public config;
    VaultManager public vaultManager;
    IERC20 public usdt;

    // ==================== 构造函数 ====================
    constructor(
        address _optionsCore,
        address _config,
        address _vaultManager,
        address _usdt,
        address _admin
    ) {
        optionsCore = IOptionsCoreForSettlement(_optionsCore);
        config = Config(_config);
        vaultManager = VaultManager(_vaultManager);
        usdt = IERC20(_usdt);
        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
    }

    // ==================== 内部辅助 ====================

    /**
     * @notice 解析价格字符串为 uint256
     */
    function _parsePrice(string memory priceStr) internal pure returns (uint256) {
        bytes memory b = bytes(priceStr);
        uint256 result = 0;
        uint256 decimals = 0;
        bool afterDot = false;
        
        for (uint256 i = 0; i < b.length; i++) {
            if (b[i] == '.') {
                afterDot = true;
                continue;
            }
            if (b[i] >= '0' && b[i] <= '9') {
                result = result * 10 + (uint8(b[i]) - 48);
                if (afterDot) decimals++;
            }
        }
        if (decimals < 18) {
            result = result * (10 ** (18 - decimals));
        }
        return result;
    }

    // ==================== 结算功能 ====================

    /**
     * @notice 买方提前行权
     */
    function earlyExercise(uint256 orderId) external override nonReentrant whenNotPaused {
        Order memory order = optionsCore.getOrder(orderId);
        require(order.orderId > 0, "Settlement: invalid order");
        require(msg.sender == order.buyer, "Settlement: not buyer");
        require(order.status == OrderStatus.LIVE, "Settlement: order not live");

        // 检查 T+X 条件
        uint256 requiredDelay = uint256(order.exerciseDelay) * 1 seconds;
        require(
            block.timestamp >= order.matchedAt + requiredDelay,
            "Settlement: exercise delay not met"
        );

        OrderStatus oldStatus = order.status;
        optionsCore.updateOrderStatus(orderId, OrderStatus.WAITING_FINAL_FEED);

        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.WAITING_FINAL_FEED, "early exercise", block.timestamp);
    }

    /**
     * @notice 到期结算
     * @dev 根据最终喂价与开仓价计算盈亏，划转资金
     *      支持分红调整 (§7.2)
     */
    function settle(uint256 orderId) external override nonReentrant whenNotPaused {
        Order memory order = optionsCore.getOrder(orderId);
        require(order.status == OrderStatus.PENDING_SETTLEMENT, "Settlement: not pending settlement");
        require(order.lastFeedPrice > 0, "Settlement: no feed price");

        // 计算盈亏 (支持分红调整)
        uint256 strikePrice = _parsePrice(order.refPrice);
        
        if (order.dividendAdjustment && order.dividendAmount > 0) {
            if (order.dividendAmount < strikePrice) {
                strikePrice = strikePrice - order.dividendAmount;
            } else {
                strikePrice = 0;
            }
        }
        uint256 finalPrice = order.lastFeedPrice;
        
        uint256 buyerProfit = 0;
        
        if (order.direction == Direction.Call) {
            if (finalPrice > strikePrice) {
                buyerProfit = (finalPrice - strikePrice) * order.notionalUSDT / strikePrice;
            }
        } else {
            if (strikePrice > finalPrice) {
                buyerProfit = (strikePrice - finalPrice) * order.notionalUSDT / strikePrice;
            }
        }

        uint256 buyerPayout = 0;
        uint256 sellerPayout = 0;
        
        if (buyerProfit > 0) {
            if (buyerProfit > order.currentMargin) {
                buyerProfit = order.currentMargin;
            }
            buyerPayout = buyerProfit;
            sellerPayout = order.currentMargin - buyerProfit;
        } else {
            sellerPayout = order.currentMargin;
        }

        // 划转资金（真实 USDT 转账）
        if (buyerPayout > 0) {
            // 从卖方内部余额转给买方，然后提现给买方钱包
            vaultManager.transferMargin(
                order.seller, order.buyer, address(usdt), buyerPayout, "settlement payout"
            );
            vaultManager.withdrawMargin(order.buyer, address(usdt), buyerPayout);
        }
        if (sellerPayout > 0) {
            // 卖方剩余保证金直接提现到卖方钱包
            vaultManager.withdrawMargin(order.seller, address(usdt), sellerPayout);
        }

        OrderStatus oldStatus = order.status;
        optionsCore.updateOrderStatus(orderId, OrderStatus.SETTLED);
        optionsCore.updateOrderSettledAt(orderId, block.timestamp);

        emit OrderSettled(orderId, buyerPayout, sellerPayout, block.timestamp);
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.SETTLED, "settled", block.timestamp);
    }

    // ==================== 保证金管理 ====================

    /**
     * @notice 卖方追加保证金
     */
    function addMargin(uint256 orderId, uint256 amount) external override nonReentrant whenNotPaused {
        require(amount > 0, "Settlement: amount must be positive");
        Order memory order = optionsCore.getOrder(orderId);
        require(msg.sender == order.seller, "Settlement: not seller");
        require(order.status == OrderStatus.LIVE, "Settlement: order not live");

        uint256 oldMargin = order.currentMargin;
        // 通过 VaultManager 正式入账（卖方保证金账户）
        vaultManager.depositMargin(msg.sender, address(usdt), amount);
        optionsCore.updateOrderMargin(orderId, order.currentMargin + amount);

        emit MarginChanged(orderId, msg.sender, oldMargin, order.currentMargin + amount, "add", block.timestamp);
    }

    /**
     * @notice 卖方提取超额保证金
     */
    function withdrawExcessMargin(uint256 orderId, uint256 amount) external override nonReentrant whenNotPaused {
        Order memory order = optionsCore.getOrder(orderId);
        require(msg.sender == order.seller, "Settlement: not seller");
        require(order.status == OrderStatus.LIVE, "Settlement: order not live");
        
        uint256 excess = order.currentMargin - order.initialMargin;
        require(amount <= excess, "Settlement: cannot withdraw below initial margin");

        uint256 oldMargin = order.currentMargin;
        optionsCore.updateOrderMargin(orderId, order.currentMargin - amount);
        vaultManager.withdrawMargin(msg.sender, address(usdt), amount);

        emit MarginChanged(orderId, msg.sender, oldMargin, order.currentMargin - amount, "withdraw", block.timestamp);
    }

    /**
     * @notice 记录标的分红 (§7.2)
     */
    function recordDividend(uint256 orderId, uint256 dividendPerShare) external override nonReentrant whenNotPaused {
        require(hasRole(DEFAULT_ADMIN_ROLE, msg.sender), "Settlement: not authorized");
        Order memory order = optionsCore.getOrder(orderId);
        require(order.status == OrderStatus.LIVE, "Settlement: order not live");
        require(order.dividendAdjustment, "Settlement: dividend adjustment not enabled");
        require(dividendPerShare > 0, "Settlement: dividend must be positive");

        optionsCore.updateOrderDividend(orderId, order.dividendAmount + dividendPerShare);

        emit DividendRecorded(orderId, dividendPerShare, order.dividendAmount + dividendPerShare, block.timestamp);
    }

    // ==================== 仲裁 ====================

    /**
     * @notice 发起仲裁
     */
    function initiateArbitration(uint256 orderId) external payable override nonReentrant whenNotPaused {
        Order memory order = optionsCore.getOrder(orderId);
        require(order.status == OrderStatus.PENDING_SETTLEMENT, "Settlement: cannot initiate arbitration");
        require(msg.sender == order.buyer || msg.sender == order.seller, "Settlement: not party to order");
        require(block.timestamp <= order.settledAt + order.arbitrationWindow, "Settlement: arbitration window closed");

        usdt.safeTransferFrom(msg.sender, address(vaultManager), config.arbitrationFee());

        OrderStatus oldStatus = order.status;
        optionsCore.updateOrderStatus(orderId, OrderStatus.ARBITRATION);

        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.ARBITRATION, "arbitration initiated", block.timestamp);
    }

    /**
     * @notice 解决仲裁 (§15.4)
     */
    function resolveArbitration(
        uint256 orderId,
        uint256 arbitrationPrice,
        address[] calldata arbitrators
    ) external override nonReentrant whenNotPaused {
        require(hasRole(DEFAULT_ADMIN_ROLE, msg.sender), "Settlement: not authorized");
        Order memory order = optionsCore.getOrder(orderId);
        require(order.status == OrderStatus.ARBITRATION, "Settlement: order not in arbitration");
        require(arbitrators.length > 0, "Settlement: no arbitrators");

        uint256 originalPrice = order.lastFeedPrice;
        address initiator = order.buyer;
        bool resultChanged = (arbitrationPrice != originalPrice);
        
        uint256 initiatorReward = 0;
        if (resultChanged) {
            initiatorReward = 11 * 1e18;
            vaultManager.transferReward(initiator, initiatorReward);
        }

        optionsCore.updateOrderPrice(orderId, arbitrationPrice);
        
        OrderStatus oldStatus = order.status;
        optionsCore.updateOrderStatus(orderId, OrderStatus.SETTLED);
        optionsCore.updateOrderSettledAt(orderId, block.timestamp);

        uint256 arbitrationId = uint256(keccak256(abi.encodePacked(orderId, block.timestamp)));

        emit ArbitrationResolved(
            orderId, arbitrationId, initiator,
            originalPrice, arbitrationPrice,
            resultChanged, initiatorReward, block.timestamp
        );
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.SETTLED, "arbitration resolved", block.timestamp);
    }

    // ==================== 清算 ====================

    /**
     * @notice 强制清算（保证金不足）
     */
    function forceLiquidate(uint256 orderId) external override nonReentrant whenNotPaused {
        Order memory order = optionsCore.getOrder(orderId);
        require(order.status == OrderStatus.LIVE, "Settlement: order not live");

        OrderStatus oldStatus = order.status;
        optionsCore.updateOrderStatus(orderId, OrderStatus.LIQUIDATED);
        optionsCore.updateOrderSettledAt(orderId, block.timestamp);

        // 清算时保证金全部赔付买方（真实 USDT 转账）
        if (order.currentMargin > 0) {
            vaultManager.transferMargin(
                order.seller, order.buyer, address(usdt), order.currentMargin, "liquidation payout"
            );
            vaultManager.withdrawMargin(order.buyer, address(usdt), order.currentMargin);
        }
        optionsCore.updateOrderMargin(orderId, 0);

        emit OrderLiquidated(orderId, order.buyer, order.currentMargin, block.timestamp);
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.LIQUIDATED, "force liquidated", block.timestamp);
    }

    /**
     * @notice 初始喂价超时取消订单 (§8.2, §15.2)
     */
    function cancelOrderDueToFeedTimeout(uint256 orderId) external override nonReentrant whenNotPaused {
        Order memory order = optionsCore.getOrder(orderId);
        require(
            order.status == OrderStatus.MATCHED || order.status == OrderStatus.WAITING_INITIAL_FEED,
            "Settlement: order not awaiting initial feed"
        );
        require(order.matchedAt > 0, "Settlement: order not matched yet");
        require(
            block.timestamp > order.matchedAt + config.initialFeedDeadline(),
            "Settlement: initial feed deadline not reached"
        );

        OrderStatus oldStatus = order.status;
        optionsCore.updateOrderStatus(orderId, OrderStatus.CANCELLED);
        optionsCore.updateOrderSettledAt(orderId, block.timestamp);

        uint256 penaltyRate = config.initialFeedPenaltyRate();
        uint256 penaltyAmount = (order.currentMargin * penaltyRate) / 10000;
        uint256 sellerRefund = order.currentMargin - penaltyAmount;

        // 退还权利金给买方（从买方内部余额提现）
        vaultManager.withdrawMargin(order.buyer, address(usdt), order.premiumAmount);
        // 违约金从卖方余额转入利润池
        if (penaltyAmount > 0) {
            vaultManager.penaltyToTreasury(order.seller, address(usdt), penaltyAmount);
        }
        // 卖方剩余保证金提现
        if (sellerRefund > 0) {
            vaultManager.withdrawMargin(order.seller, address(usdt), sellerRefund);
        }
        optionsCore.updateOrderMargin(orderId, 0);

        emit OrderCancelled(orderId, "initial feed timeout", block.timestamp);
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.CANCELLED, "initial feed timeout", block.timestamp);
        emit MarginChanged(orderId, order.seller, order.currentMargin, 0, "penalty_deducted", block.timestamp);
    }

    /**
     * @notice 触发追保 (P0 追保机制)
     */
    function triggerMarginCall(uint256 orderId, bool isCrypto) external override nonReentrant whenNotPaused {
        Order memory order = optionsCore.getOrder(orderId);
        require(order.status == OrderStatus.LIVE, "Settlement: order not live");
        require(order.marginCallDeadline == 0, "Settlement: margin call already triggered");

        uint256 minRequired = (order.initialMargin * order.minMarginRate) / 10000;
        require(order.currentMargin < minRequired, "Settlement: margin sufficient");

        uint256 deadline = block.timestamp + config.getMarginCallDeadline(isCrypto);
        optionsCore.updateOrderMarginCallDeadline(orderId, deadline);

        emit MarginCallTriggered(orderId, order.seller, order.currentMargin, minRequired, deadline);
    }

    /**
     * @notice 追保超时强制清算
     */
    function forceLiquidateMarginCall(uint256 orderId) external override nonReentrant whenNotPaused {
        Order memory order = optionsCore.getOrder(orderId);
        require(order.status == OrderStatus.LIVE, "Settlement: order not live");
        require(order.marginCallDeadline > 0, "Settlement: no margin call active");
        require(block.timestamp > order.marginCallDeadline, "Settlement: deadline not reached");

        uint256 minRequired = (order.initialMargin * order.minMarginRate) / 10000;
        require(order.currentMargin < minRequired, "Settlement: margin was restored");

        OrderStatus oldStatus = order.status;
        optionsCore.updateOrderStatus(orderId, OrderStatus.LIQUIDATED);
        optionsCore.updateOrderSettledAt(orderId, block.timestamp);

        uint256 buyerPayout = order.currentMargin;
        if (buyerPayout > 0) {
            // 从卖方余额转给买方，然后提现给买方钱包
            vaultManager.transferMargin(
                order.seller, order.buyer, address(usdt), buyerPayout, "margin call liquidation"
            );
            vaultManager.withdrawMargin(order.buyer, address(usdt), buyerPayout);
        }
        optionsCore.updateOrderMargin(orderId, 0);
        optionsCore.updateOrderMarginCallDeadline(orderId, 0);

        emit OrderLiquidated(orderId, order.buyer, buyerPayout, block.timestamp);
        emit OrderStatusChanged(orderId, oldStatus, OrderStatus.LIQUIDATED, "margin call timeout", block.timestamp);
    }

    // ==================== 管理功能 ====================

    function setOptionsCore(address _optionsCore) external onlyRole(DEFAULT_ADMIN_ROLE) {
        optionsCore = IOptionsCoreForSettlement(_optionsCore);
    }

    function setConfig(address _config) external onlyRole(DEFAULT_ADMIN_ROLE) {
        config = Config(_config);
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

